def SatPressFromTemp(T: Float64) -> Float64:
    var Tk = T + Constant.Kelvin
    var lnP = -5800.2206/Tk + 1.3914993 - 0.04860239*Tk + 0.41764768e-4*pow_2(Tk) - 0.14452093e-7*pow_3(Tk) + 6.5459673*log(Tk)
    return exp(lnP)

def RadExchangeNet(eps: Float64, Ts: Float64, Tsurr: Float64) -> Float64:
    var Tsk = Ts + Constant.Kelvin
    var Tsurrk = Tsurr + Constant.Kelvin
    return eps * Constant.StefanBoltzmann * (pow_4(Tsk) - pow_4(Tsurrk))

def MeanRadiantTemp(T1: Float64, A1: Float64, T2: Float64, A2: Float64) -> Float64:
    var T1k = T1 + Constant.Kelvin
    var T2k = T2 + Constant.Kelvin
    var w = (A1*pow_4(T1k) + A2*pow_4(T2k))/(A1 + A2)
    return root_4(w) - Constant.Kelvin

def HumRatioFromVapPress(Pw: Float64, Pb: Float64) -> Float64:
    var W = 0.62198*Pw/(Pb - Pw)
    if W < 1.0e-5:
        W = 1.0e-5
    return W

def MoistAirDensity(Pb: Float64, Tdb: Float64, W: Float64) -> Float64:
    var Tk = Tdb + Constant.Kelvin
    return Pb/(287.055*Tk*(1.0 + 1.6077687*W))

def DewPointFromVapPress(Pw: Float64) -> Float64:
    var lnPw = log(Pw/1000.0)
    var Tdp: Float64
    if lnPw < 0.0:
        Tdp = 6.09 + 12.608*lnPw + 0.4959*pow_2(lnPw)
    else:
        Tdp = 6.54 + 14.526*lnPw + 0.7389*pow_2(lnPw) + 0.09486*pow_3(lnPw) + 0.4569*((Pw/1000.0) ** 0.1984)
    return Tdp

def LogMeanTempDiff(dT1: Float64, dT2: Float64) -> Float64:
    if abs(dT1 - dT2) < 1.0e-6:
        return 0.5*(dT1 + dT2)
    return (dT1 - dT2)/log(dT1/dT2)

def NTUeffectivenessCounter(NTU: Float64, Cr: Float64) -> Float64:
    if Cr > 0.999:
        return NTU/(1.0 + NTU)
    var e = exp(-NTU*(1.0 - Cr))
    return (1.0 - e)/(1.0 - Cr*e)

def FinEfficiency(h: Float64, k: Float64, th: Float64, L: Float64) -> Float64:
    var m = sqrt(2.0*h/(k*th))
    var mL = m*L
    var e = exp(mL)
    var em = exp(-mL)
    var tanhmL = (e - em)/(e + em)
    return tanhmL/mL

def NusseltDittusBoelter(Re: Float64, Pr: Float64, heating: Bool) -> Float64:
    var n = 0.4 if heating else 0.3
    return 0.023*(Re ** 0.8)*(Pr ** n)

def SkyTempClark(Tdb: Float64, Tdp: Float64, opaqueFrac: Float64) -> Float64:
    var Tk = Tdb + Constant.Kelvin
    var emiss = (0.787 + 0.764*log((Tdp + Constant.Kelvin)/273.0))*(1.0 + 0.0224*opaqueFrac)
    return (emiss ** 0.25)*Tk - Constant.Kelvin

def GroundTempSeasonalPoly(Tmean: Float64, Tamp: Float64, dayOfYear: Float64) -> Float64:
    var f = mod(dayOfYear - 1.0, 365.0)/365.0
    var shape = -16.0*pow_2(f)*pow_2(1.0 - f)
    return Tmean + Tamp*shape

def HeatingDegreeDays(Tbase: Float64, Tavg: Float64) -> Float64:
    var dd = Tbase - Tavg
    return 0.5*(dd + abs(dd))

def WetBulbApproxPoly(Tdb: Float64, RH: Float64) -> Float64:
    var r = RH/100.0
    var Twb = Tdb - (1.0 - r)*(0.55 + 0.007*Tdb)*(14.0 + 0.5*Tdb)
    if Twb > Tdb:
        Twb = Tdb
    return Twb

def ThermalResistanceSeries(Rsi: Float64, Lins: Float64, kins: Float64, Rso: Float64) -> Float64:
    var Rtot = Rsi + Lins/kins + Rso
    return 1.0/Rtot

def SolarHourAngle(localHour: Float64) -> Float64:
    var h = mod(localHour + 12.0, 24.0) - 12.0
    return 15.0*h*Constant.DegToRad

def PMVThermalLoad(M: Float64, Tcl: Float64, Tr: Float64, Ta: Float64) -> Float64:
    var Tclk = Tcl + Constant.Kelvin
    var Trk = Tr + Constant.Kelvin
    var rad = 3.96e-8*(pow_4(Tclk) - pow_4(Trk))
    var conv = 12.1*sqrt(0.1)*(Tcl - Ta)
    return (0.303*exp(-0.036*M) + 0.028)*(M - rad - conv)

def MoistAirEnth2(Tdb: Float64, W: Float64) -> Float64:
    return 1.00484e3*Tdb + W*(2.50094e6 + 1.85895e3*Tdb)

def EnthalpyDiffClamp(Tdb: Float64, W: Float64) -> Float64:
    var h = MoistAirEnth2(Tdb, W)
    if h < 0.0:
        h = 0.0
    if h > 1.0e5:
        h = 1.0e5
    return h

def RhoCpProduct(Tdb: Float64) -> Float64:
    var Tk = Tdb + Constant.Kelvin
    var rho = 101325.0/(287.055*Tk)
    var cp = 1004.84
    return rho*cp

def SignedHeatFlux(U: Float64, Tin: Float64, Tout: Float64) -> Float64:
    var dT = Tin - Tout
    var q = U*abs(dT)
    return sign(q, dT)
